import { Group } from '@visx/group';
import { type MouseEventHandler, useRef } from 'react';

import {
  MARKER_STROKE_WIDTH,
  MARKER_STROKE_COLOR,
  MARKER_RADIUS,
  MARKER_OPACITY,
} from './constants.js';
import { useId } from '../../../../../core/hooks/useId.js';
import { useMouseHover } from '../../../hooks/useMouseHover.js';
import { ThresholdBrightnessFilter } from '../ThresholdBrightnessFilter.js';

export interface CircleMarkerProps {
  x: number;
  y: number;
  color: string;
  onMouseMove: MouseEventHandler;
  onMouseLeave: MouseEventHandler;
}

export const CircleMarker = (props: CircleMarkerProps) => {
  const { x, y, color, onMouseMove, onMouseLeave } = props;

  const circleRef = useRef<SVGCircleElement>(null);
  const hovered = useMouseHover(circleRef);
  const id = useId();

  const brightnessFilterId = `threshold-circle-marker-filter-${id}`;

  return (
    <Group>
      <ThresholdBrightnessFilter id={brightnessFilterId} />
      <circle
        role="graphics-symbol"
        aria-label="circle marker"
        ref={circleRef}
        opacity={MARKER_OPACITY}
        stroke={MARKER_STROKE_COLOR}
        strokeWidth={MARKER_STROKE_WIDTH}
        cx={x}
        cy={y}
        r={MARKER_RADIUS}
        fill={color}
        onMouseMove={onMouseMove}
        onMouseLeave={onMouseLeave}
        filter={hovered ? `url(#${brightnessFilterId})` : undefined}
      />
    </Group>
  );
};
